import React, { useState, useMemo } from 'react';

// Mock warranty claims data
const MOCK_CLAIMS = [
  { id: 'C001', productName: 'Laptop X1', customerName: 'Alice Smith', claimDate: '2023-01-15', status: 'Approved', claimAmount: 1200.00 },
  { id: 'C002', productName: 'Smartphone Y2', customerName: 'Bob Johnson', claimDate: '2023-02-01', status: 'Pending', claimAmount: 750.00 },
  { id: 'C003', productName: 'Monitor Z3', customerName: 'Charlie Brown', claimDate: '2023-01-20', status: 'Rejected', claimAmount: 300.00 },
  { id: 'C004', productName: 'Keyboard K4', customerName: 'Diana Prince', claimDate: '2023-03-10', status: 'Pending', claimAmount: 80.00 },
  { id: 'C005', productName: 'Mouse M5', customerName: 'Ethan Hunt', claimDate: '2023-02-25', status: 'Approved', claimAmount: 35.00 },
  { id: 'C006', productName: 'Laptop X1', customerName: 'Fiona Apple', claimDate: '2023-03-05', status: 'Pending', claimAmount: 1300.00 },
  { id: 'C007', productName: 'Tablet T6', customerName: 'George Clooney', claimDate: '2023-01-28', status: 'Approved', claimAmount: 600.00 },
  { id: 'C008', productName: 'Speaker S7', customerName: 'Hannah Montana', claimDate: '2023-02-18', status: 'Rejected', claimAmount: 150.00 },
  { id: 'C009', productName: 'Webcam W8', customerName: 'Ian Somerhalder', claimDate: '2023-03-12', status: 'Pending', claimAmount: 70.00 },
  { id: 'C010', productName: 'Headphones H9', customerName: 'Julia Roberts', claimDate: '2023-01-05', status: 'Approved', claimAmount: 200.00 },
  { id: 'C011', productName: 'Smartwatch S1', customerName: 'Kevin Lee', claimDate: '2023-02-14', status: 'Approved', claimAmount: 250.00 },
  { id: 'C012', productName: 'External Drive E1', customerName: 'Laura Miller', claimDate: '2023-03-01', status: 'Pending', claimAmount: 100.00 },
];

const WarrantyClaimsDashboard = () => {
  // State for the original claims data (assuming it's static for this example)
  const [claims] = useState(MOCK_CLAIMS);

  // State for sorting configuration
  const [sortConfig, setSortConfig] = useState({ key: 'claimDate', direction: 'desc' }); // Default sort by date desc

  // State for filter values
  const [filters, setFilters] = useState({
    productName: '',
    status: '',
    claimDateFrom: '',
    claimDateTo: ''
  });

  // Handler for changing sort configuration
  const handleSort = (key) => {
    let direction = 'asc';
    // If the same key is clicked, toggle the direction
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  // Handler for filter input changes
  const handleFilterChange = (e) => {
    const { name, value } = e.target;
    setFilters(prevFilters => ({
      ...prevFilters,
      [name]: value
    }));
  };

  // Memoized value for filtered and sorted claims
  // This re-calculates only when claims, filters, or sortConfig change
  const processedClaims = useMemo(() => {
    let currentClaims = [...claims]; // Create a mutable copy to sort/filter

    // 1. Apply Filters
    currentClaims = currentClaims.filter(claim => {
      const productNameMatch = claim.productName.toLowerCase().includes(filters.productName.toLowerCase());
      const statusMatch = filters.status === '' || claim.status === filters.status;

      const claimDate = new Date(claim.claimDate); // Convert claim date string to Date object
      const dateFrom = filters.claimDateFrom ? new Date(filters.claimDateFrom) : null;
      const dateTo = filters.claimDateTo ? new Date(filters.claimDateTo) : null;

      const dateFromMatch = !dateFrom || claimDate >= dateFrom;
      // To include the whole 'dateTo' day, compare against the end of that day.
      // For simplicity, we compare directly, meaning if filter '2023-01-31' it matches '2023-01-31 00:00:00'.
      // If a full day range is needed, dateTo could be modified to `new Date(filters.claimDateTo + 'T23:59:59.999Z')`.
      const dateToMatch = !dateTo || claimDate <= dateTo;

      return productNameMatch && statusMatch && dateFromMatch && dateToMatch;
    });

    // 2. Apply Sorting
    if (sortConfig.key) {
      currentClaims.sort((a, b) => {
        const aValue = a[sortConfig.key];
        const bValue = b[sortConfig.key];

        let comparison = 0;
        if (sortConfig.key === 'claimDate') {
          // Compare dates numerically
          const dateA = new Date(aValue);
          const dateB = new Date(bValue);
          comparison = dateA.getTime() - dateB.getTime();
        } else if (typeof aValue === 'string') {
          // String comparison
          comparison = aValue.localeCompare(bValue);
        } else if (typeof aValue === 'number') {
          // Numeric comparison
          comparison = aValue - bValue;
        }

        // Apply ascending or descending direction
        return sortConfig.direction === 'asc' ? comparison : -comparison;
      });
    }

    return currentClaims;
  }, [claims, filters, sortConfig]); // Dependencies for useMemo

  // Helper to render sort arrow indicators
  const renderSortIndicator = (key) => {
    if (sortConfig.key === key) {
      return sortConfig.direction === 'asc' ? ' ▲' : ' ▼';
    }
    return null;
  };

  return (
    <div className="warranty-dashboard">
      <h1>Warranty Claims Dashboard</h1>

      {/* Filters Section */}
      <div className="filters-container">
        <div className="filter-group">
          <label htmlFor="productName">Product Name:</label>
          <input
            type="text"
            id="productName"
            name="productName"
            value={filters.productName}
            onChange={handleFilterChange}
            placeholder="Filter by product name"
          />
        </div>

        <div className="filter-group">
          <label htmlFor="status">Status:</label>
          <select
            id="status"
            name="status"
            value={filters.status}
            onChange={handleFilterChange}
          >
            <option value="">All</option>
            <option value="Pending">Pending</option>
            <option value="Approved">Approved</option>
            <option value="Rejected">Rejected</option>
          </select>
        </div>

        <div className="filter-group">
          <label htmlFor="claimDateFrom">Claim Date From:</label>
          <input
            type="date"
            id="claimDateFrom"
            name="claimDateFrom"
            value={filters.claimDateFrom}
            onChange={handleFilterChange}
          />
        </div>

        <div className="filter-group">
          <label htmlFor="claimDateTo">Claim Date To:</label>
          <input
            type="date"
            id="claimDateTo"
            name="claimDateTo"
            value={filters.claimDateTo}
            onChange={handleFilterChange}
          />
        </div>
      </div>

      {/* Claims Table Section */}
      <div className="claims-table-container">
        {processedClaims.length > 0 ? (
          <table>
            <thead>
              <tr>
                <th onClick={() => handleSort('id')}>Claim ID {renderSortIndicator('id')}</th>
                <th onClick={() => handleSort('productName')}>Product Name {renderSortIndicator('productName')}</th>
                <th onClick={() => handleSort('customerName')}>Customer Name {renderSortIndicator('customerName')}</th>
                <th onClick={() => handleSort('claimDate')}>Claim Date {renderSortIndicator('claimDate')}</th>
                <th onClick={() => handleSort('status')}>Status {renderSortIndicator('status')}</th>
                <th onClick={() => handleSort('claimAmount')}>Amount {renderSortIndicator('claimAmount')}</th>
              </tr>
            </thead>
            <tbody>
              {processedClaims.map(claim => (
                <tr key={claim.id}>
                  <td>{claim.id}</td>
                  <td>{claim.productName}</td>
                  <td>{claim.customerName}</td>
                  <td>{new Date(claim.claimDate).toLocaleDateString()}</td>
                  <td>{claim.status}</td>
                  <td>{claim.claimAmount.toLocaleString('en-US', { style: 'currency', currency: 'USD' })}</td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <p className="no-claims-message">No claims found matching your criteria.</p>
        )}
      </div>

      {/* Basic Styles for the component */}
      <style jsx>{`
        .warranty-dashboard {
          font-family: Arial, sans-serif;
          padding: 20px;
          max-width: 1200px;
          margin: 0 auto;
        }

        h1 {
          text-align: center;
