document.addEventListener('DOMContentLoaded', () => {
    initCharts(); // Initialize charts when the DOM is loaded

    const sidebarLinks = document.querySelectorAll('.dashboard-sidebar ul li a');
    const dashboardContent = document.querySelector('.dashboard-content');

    sidebarLinks.forEach(link => {
        link.addEventListener('click', function(e) {
            e.preventDefault();
            const targetId = this.getAttribute('href').substring(1);
            const targetSection = document.getElementById(targetId);

            // Remove active class from all links
            sidebarLinks.forEach(l => l.classList.remove('active'));
            // Add active class to the clicked link
            this.classList.add('active');

            // Scroll to the target section
            if (targetSection) {
                // Use dashboardContent for scrolling if it's the scrollable container
                dashboardContent.scrollTo({
                    top: targetSection.offsetTop - dashboardContent.offsetTop, // Adjust for parent's scroll position
                    behavior: 'smooth'
                });
            }
        });
    });

    // Set initial active state for overview or first link
    if (sidebarLinks.length > 0) {
        sidebarLinks[0].classList.add('active');
    }

    // --- Sales Trends Filter Interactivity ---
    const salesFilterQuarterBtn = document.getElementById('salesFilterQuarter');
    const salesFilterMonthBtn = document.getElementById('salesFilterMonth');

    salesFilterQuarterBtn.addEventListener('click', () => {
        updateSalesChart(salesDataQuarterly, 'Quarterly Sales Revenue', salesFilterQuarterBtn, salesFilterMonthBtn);
    });

    salesFilterMonthBtn.addEventListener('click', () => {
        updateSalesChart(salesDataMonthly, 'Monthly Sales Revenue (Current Year)', salesFilterMonthBtn, salesFilterQuarterBtn);
    });
});

function updateSalesChart(newData, newTitle, activeBtn, inactiveBtn) {
    if (salesTrendChart) {
        salesTrendChart.data = newData;
        salesTrendChart.options.plugins.title.text = newTitle;
        salesTrendChart.update();

        activeBtn.classList.add('active');
        inactiveBtn.classList.remove('active');
    }
}

